import { useEffect, useState, useRef } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { useAuth } from "@/contexts/AuthContext";
import { useLoginRequired } from "@/hooks/useLoginRequired";
import { SignatureDishList, type SignatureDish } from "@/components/chef/SignatureDishList";
import { InlineSignatureDishEditor } from "@/components/chef/InlineSignatureDishEditor";

interface ChefRecommendedDishesProps {
  restaurantId: string;
  isEditMode?: boolean;
  canEdit?: boolean;
}

const dishTranslationCache = new Map<string, string>();

export const ChefRecommendedDishes = ({ restaurantId, isEditMode = false, canEdit = false }: ChefRecommendedDishesProps) => {
  const { i18n } = useTranslation();
  const { currentLang } = useLocalizedContent();
  const { user } = useAuth();
  const { requireLogin } = useLoginRequired();
  const [signatureDishes, setSignatureDishes] = useState<SignatureDish[]>([]);
  const [loading, setLoading] = useState(true);
  const [expandedDish, setExpandedDish] = useState<string | null>(null);
  const [neijingTranslations, setNeijingTranslations] = useState<Record<string, { text: string; showTranslated: boolean }>>({});
  const [translatingDishId, setTranslatingDishId] = useState<string | null>(null);
  const [autoTranslatedDishes, setAutoTranslatedDishes] = useState<Record<string, { name?: string; description?: string }>>({});
  const autoTranslateAttempted = useRef<string | null>(null);
  const [userLikes, setUserLikes] = useState<Set<string>>(new Set());
  const [likingDishId, setLikingDishId] = useState<string | null>(null);
  const [userWants, setUserWants] = useState<Set<string>>(new Set());
  const [wantingDishId, setWantingDishId] = useState<string | null>(null);

  useEffect(() => {
    const fetchDishes = async () => {
      setLoading(true);
      const { data, error } = await supabase
        .from("chef_signature_dishes" as any)
        .select("*")
        .eq("restaurant_id", restaurantId)
        .order("sort_order");

      if (!error && data) setSignatureDishes(data as unknown as SignatureDish[]);
      setLoading(false);
    };

    void fetchDishes();
  }, [restaurantId]);

  useEffect(() => {
    if (!user || signatureDishes.length === 0 || isEditMode) return;
    const dishIds = signatureDishes.map((d) => d.id).filter((id) => !id.startsWith("draft-"));
    if (!dishIds.length) return;

    const fetchReactions = async () => {
      const [likesRes, wantsRes] = await Promise.all([
        supabase.from("chef_signature_dish_likes" as any).select("dish_id").eq("user_id", user.id).in("dish_id", dishIds),
        supabase.from("chef_signature_dish_wants" as any).select("dish_id").eq("user_id", user.id).in("dish_id", dishIds),
      ]);

      if (likesRes.data) setUserLikes(new Set((likesRes.data as any[]).map((row: any) => row.dish_id)));
      if (wantsRes.data) setUserWants(new Set((wantsRes.data as any[]).map((row: any) => row.dish_id)));
    };

    void fetchReactions();
  }, [user, signatureDishes, isEditMode]);

  useEffect(() => {
    if (signatureDishes.length === 0 || isEditMode) return;
    const hasNativeColumn = ["zh", "en", "pt"].includes(currentLang);
    if (hasNativeColumn) return;

    const fingerprint = `${currentLang}_${signatureDishes.map((d) => d.id).join(",")}`;
    if (autoTranslateAttempted.current === fingerprint) return;
    autoTranslateAttempted.current = fingerprint;

    const textsToTranslate: { dishId: string; field: string; text: string }[] = [];

    signatureDishes.forEach((dish) => {
      const name = dish.dish_name_en || dish.dish_name_zh || "";
      const desc = dish.description_en || dish.description_zh || "";

      if (name && !dishTranslationCache.has(`dish_name_${dish.id}_${currentLang}`)) {
        textsToTranslate.push({ dishId: dish.id, field: "name", text: name });
      }
      if (desc && !dishTranslationCache.has(`dish_desc_${dish.id}_${currentLang}`)) {
        textsToTranslate.push({ dishId: dish.id, field: "description", text: desc });
      }
    });

    const cached: Record<string, { name?: string; description?: string }> = {};
    signatureDishes.forEach((dish) => {
      const cachedName = dishTranslationCache.get(`dish_name_${dish.id}_${currentLang}`);
      const cachedDesc = dishTranslationCache.get(`dish_desc_${dish.id}_${currentLang}`);
      if (cachedName || cachedDesc) {
        cached[dish.id] = { name: cachedName, description: cachedDesc };
      }
    });

    if (Object.keys(cached).length > 0) setAutoTranslatedDishes(cached);
    if (textsToTranslate.length === 0) return;

    const separator = "\n---DISH_SEP---\n";
    const combinedText = textsToTranslate.map((item) => item.text).join(separator);

    supabase.functions
      .invoke("translate-content", { body: { text: combinedText, targetLang: currentLang } })
      .then(({ data, error }) => {
        if (!error && data?.translatedText) {
          const parts = data.translatedText.split(/---DISH_SEP---/);
          const result: Record<string, { name?: string; description?: string }> = { ...cached };

          textsToTranslate.forEach((item, idx) => {
            const translated = parts[idx]?.trim();
            if (!translated) return;

            const cacheKey = item.field === "name"
              ? `dish_name_${item.dishId}_${currentLang}`
              : `dish_desc_${item.dishId}_${currentLang}`;

            dishTranslationCache.set(cacheKey, translated);
            if (!result[item.dishId]) result[item.dishId] = {};
            if (item.field === "name") result[item.dishId].name = translated;
            else result[item.dishId].description = translated;
          });

          setAutoTranslatedDishes(result);
        }
      })
      .catch(() => undefined);
  }, [signatureDishes, currentLang, isEditMode]);

  const handleLikeDish = async (dishId: string) => {
    if (!requireLogin() || likingDishId) return;
    setLikingDishId(dishId);
    const isLiked = userLikes.has(dishId);

    setUserLikes((prev) => {
      const next = new Set(prev);
      if (isLiked) next.delete(dishId);
      else next.add(dishId);
      return next;
    });
    setSignatureDishes((prev) => prev.map((d) => (d.id === dishId ? { ...d, likes_count: d.likes_count + (isLiked ? -1 : 1) } : d)));

    try {
      if (isLiked) {
        await supabase.from("chef_signature_dish_likes" as any).delete().eq("dish_id", dishId).eq("user_id", user!.id);
      } else {
        await supabase.from("chef_signature_dish_likes" as any).insert({ dish_id: dishId, user_id: user!.id } as any);
      }
    } catch {
      setUserLikes((prev) => {
        const next = new Set(prev);
        if (isLiked) next.add(dishId);
        else next.delete(dishId);
        return next;
      });
      setSignatureDishes((prev) => prev.map((d) => (d.id === dishId ? { ...d, likes_count: d.likes_count + (isLiked ? 1 : -1) } : d)));
    }

    setLikingDishId(null);
  };

  const handleWantDish = async (dishId: string) => {
    if (!requireLogin() || wantingDishId) return;
    setWantingDishId(dishId);
    const isWanted = userWants.has(dishId);

    setUserWants((prev) => {
      const next = new Set(prev);
      if (isWanted) next.delete(dishId);
      else next.add(dishId);
      return next;
    });
    setSignatureDishes((prev) => prev.map((d) => (d.id === dishId ? { ...d, wants_count: (d.wants_count || 0) + (isWanted ? -1 : 1) } : d)));

    try {
      if (isWanted) {
        await supabase.from("chef_signature_dish_wants" as any).delete().eq("dish_id", dishId).eq("user_id", user!.id);
      } else {
        await supabase.from("chef_signature_dish_wants" as any).insert({ dish_id: dishId, user_id: user!.id } as any);
      }
    } catch {
      setUserWants((prev) => {
        const next = new Set(prev);
        if (isWanted) next.add(dishId);
        else next.delete(dishId);
        return next;
      });
      setSignatureDishes((prev) => prev.map((d) => (d.id === dishId ? { ...d, wants_count: (d.wants_count || 0) + (isWanted ? 1 : -1) } : d)));
    }

    setWantingDishId(null);
  };

  const getDishNeijing = (dish: SignatureDish) => dish.neijing_zh || dish.neijing_en || dish.neijing_pt || "";

  const handleTranslateNeijing = async (dish: SignatureDish) => {
    const existing = neijingTranslations[dish.id];
    if (existing) {
      setNeijingTranslations((prev) => ({
        ...prev,
        [dish.id]: { ...prev[dish.id], showTranslated: !prev[dish.id].showTranslated },
      }));
      return;
    }

    const neijingText = getDishNeijing(dish);
    if (!neijingText) return;

    setTranslatingDishId(dish.id);
    try {
      const { data, error } = await supabase.functions.invoke("translate-content", {
        body: { text: neijingText, targetLang: i18n.language },
      });

      if (!error && data?.translatedText) {
        setNeijingTranslations((prev) => ({
          ...prev,
          [dish.id]: { text: data.translatedText, showTranslated: true },
        }));
      }
    } catch {
      // noop
    }
    setTranslatingDishId(null);
  };

  const isCoreLang = currentLang === "zh";
  if (loading || (signatureDishes.length === 0 && !isEditMode)) return null;

  return (
    <section className="py-8 md:py-10">
      <div className="container mx-auto max-w-4xl px-4">
        {isEditMode && canEdit ? (
          <InlineSignatureDishEditor restaurantId={restaurantId} dishes={signatureDishes} onChange={setSignatureDishes} />
        ) : (
          <SignatureDishList
            dishes={signatureDishes}
            currentLang={currentLang}
            expandedDish={expandedDish}
            setExpandedDish={setExpandedDish}
            autoTranslatedDishes={autoTranslatedDishes}
            neijingTranslations={neijingTranslations}
            translatingDishId={translatingDishId}
            currentUserLikes={userLikes}
            currentUserWants={userWants}
            isCoreLang={isCoreLang}
            onLike={handleLikeDish}
            onWant={handleWantDish}
            onTranslateNeijing={handleTranslateNeijing}
          />
        )}
      </div>
    </section>
  );
};
