import { useRef, useState } from "react";
import { Plus, Save, Trash2, ImagePlus, Loader2, Pencil, Sparkles, RefreshCw } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";

export interface EditableSignatureDish {
  id: string;
  dish_name_zh: string;
  dish_name_en: string | null;
  dish_name_pt: string | null;
  description_zh: string | null;
  description_en: string | null;
  description_pt: string | null;
  neijing_zh: string | null;
  neijing_en: string | null;
  neijing_pt: string | null;
  image_url: string | null;
  sort_order: number | null;
  likes_count: number;
  wants_count: number;
}

interface InlineSignatureDishEditorProps {
  restaurantId: string;
  dishes: EditableSignatureDish[];
  onChange: (dishes: EditableSignatureDish[]) => void;
}

const createEmptyDish = (sortOrder: number): EditableSignatureDish => ({
  id: `draft-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
  dish_name_zh: "",
  dish_name_en: "",
  dish_name_pt: "",
  description_zh: "",
  description_en: "",
  description_pt: "",
  neijing_zh: "",
  neijing_en: "",
  neijing_pt: "",
  image_url: null,
  sort_order: sortOrder,
  likes_count: 0,
  wants_count: 0,
});

export const InlineSignatureDishEditor = ({ restaurantId, dishes, onChange }: InlineSignatureDishEditorProps) => {
  const [savingIds, setSavingIds] = useState<string[]>([]);
  const [deletingIds, setDeletingIds] = useState<string[]>([]);
  const [generatingNeijingIds, setGeneratingNeijingIds] = useState<string[]>([]);
  const fileInputsRef = useRef<Record<string, HTMLInputElement | null>>({});

  const uploadDishImage = async (file: File) => {
    const ext = file.name.split(".").pop() || "jpg";
    const fileName = `${restaurantId}/signature-${Date.now()}-${Math.random().toString(36).slice(2, 8)}.${ext}`;
    const { error } = await supabase.storage.from("restaurant-images").upload(fileName, file);
    if (error) throw error;
    return supabase.storage.from("restaurant-images").getPublicUrl(fileName).data.publicUrl;
  };

  const updateDish = (dishId: string, updates: Partial<EditableSignatureDish>) => {
    onChange(dishes.map((dish) => (dish.id === dishId ? { ...dish, ...updates } : dish)));
  };

  const handleAddDish = () => {
    onChange([...dishes, createEmptyDish(dishes.length)]);
  };

  const handleSaveDish = async (dish: EditableSignatureDish) => {
    if (!dish.dish_name_zh.trim()) {
      toast.error("请先填写菜品标题");
      return;
    }

    setSavingIds((prev) => [...prev, dish.id]);
    try {
      const payload = {
        restaurant_id: restaurantId,
        dish_name_zh: dish.dish_name_zh.trim(),
        dish_name_en: dish.dish_name_zh.trim(),
        dish_name_pt: dish.dish_name_zh.trim(),
        description_zh: dish.description_zh || null,
        description_en: dish.description_zh || null,
        description_pt: dish.description_zh || null,
        image_url: dish.image_url || null,
        sort_order: dish.sort_order ?? 0,
      };

      if (dish.id.startsWith("draft-")) {
        const { data, error } = await supabase
          .from("chef_signature_dishes" as any)
          .insert(payload)
          .select("*")
          .single();
        if (error) throw error;
        onChange(dishes.map((item) => (item.id === dish.id ? (data as unknown as EditableSignatureDish) : item)));
      } else {
        const { data, error } = await supabase
          .from("chef_signature_dishes" as any)
          .update(payload)
          .eq("id", dish.id)
          .select("*")
          .single();
        if (error) throw error;
        onChange(dishes.map((item) => (item.id === dish.id ? (data as unknown as EditableSignatureDish) : item)));
      }
      toast.success("菜品已保存");
    } catch (error: any) {
      toast.error(error.message || "保存失败");
    } finally {
      setSavingIds((prev) => prev.filter((id) => id !== dish.id));
    }
  };

  const handleDeleteDish = async (dish: EditableSignatureDish) => {
    if (dish.id.startsWith("draft-")) {
      onChange(dishes.filter((item) => item.id !== dish.id));
      return;
    }

    setDeletingIds((prev) => [...prev, dish.id]);
    try {
      const { error } = await supabase.from("chef_signature_dishes" as any).delete().eq("id", dish.id);
      if (error) throw error;
      onChange(dishes.filter((item) => item.id !== dish.id));
      toast.success("菜品已删除");
    } catch (error: any) {
      toast.error(error.message || "删除失败");
    } finally {
      setDeletingIds((prev) => prev.filter((id) => id !== dish.id));
    }
  };

  const handleRegenerateNeijing = async (dish: EditableSignatureDish) => {
    if (dish.id.startsWith("draft-")) {
      toast.error("请先保存菜品后再生成解读");
      return;
    }
    setGeneratingNeijingIds((prev) => [...prev, dish.id]);
    try {
      const { data, error } = await supabase.functions.invoke("generate-signature-dish-neijing", {
        body: { restaurant_id: restaurantId, dish_id: dish.id },
      });
      if (error) throw error;
      if (data?.neijing_zh) {
        updateDish(dish.id, {
          neijing_zh: data.neijing_zh,
          neijing_en: data.neijing_en || data.neijing_zh,
          neijing_pt: data.neijing_pt || data.neijing_zh,
        });
        toast.success("《黄帝内经》解读已重新生成");
      }
    } catch (error: any) {
      toast.error(error.message || "生成失败，请稍后重试");
    } finally {
      setGeneratingNeijingIds((prev) => prev.filter((id) => id !== dish.id));
    }
  };

  const handleImageChange = async (dishId: string, file?: File | null) => {
    if (!file) return;
    try {
      const imageUrl = await uploadDishImage(file);
      updateDish(dishId, { image_url: imageUrl });
      toast.success("图片已更新");
    } catch (error: any) {
      toast.error(error.message || "图片上传失败");
    }
  };

  return (
    <section className="space-y-5">
      <div className="flex flex-col gap-3 rounded-3xl border-2 border-primary/35 bg-card/95 p-5 shadow-sm md:flex-row md:items-center md:justify-between">
        <div>
          <p className="flex items-center gap-2 text-sm font-semibold text-primary">
            <Pencil className="h-4 w-4" />
            可编辑区域 · 菜品详解
          </p>
          <p className="mt-1 text-sm text-muted-foreground">可新增、编辑、删除多个招牌菜；《黄帝内经》解读仅展示系统生成结果，不可手动编辑。</p>
        </div>
        <Button type="button" onClick={handleAddDish}>
          <Plus className="h-4 w-4" />
          新增招牌菜
        </Button>
      </div>

      <div className="grid gap-5">
        {dishes.map((dish, index) => {
          const isSaving = savingIds.includes(dish.id);
          const isDeleting = deletingIds.includes(dish.id);

          return (
            <Card key={dish.id} className="overflow-hidden border-border/60 shadow-sm">
              <CardHeader className="border-b border-border/50 bg-muted/20">
                <div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
                  <CardTitle className="flex items-center gap-3 text-lg">
                    <span className="flex h-9 w-9 items-center justify-center rounded-full bg-primary/10 text-sm font-bold text-primary">{index + 1}</span>
                    招牌菜 #{index + 1}
                  </CardTitle>
                  <div className="flex items-center gap-2">
                    <Button type="button" variant="outline" onClick={() => handleSaveDish(dish)} disabled={isSaving || isDeleting}>
                      {isSaving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                      保存
                    </Button>
                    <Button type="button" variant="destructive" onClick={() => handleDeleteDish(dish)} disabled={isSaving || isDeleting}>
                      {isDeleting ? <Loader2 className="h-4 w-4 animate-spin" /> : <Trash2 className="h-4 w-4" />}
                      删除
                    </Button>
                  </div>
                </div>
              </CardHeader>
              <CardContent className="grid gap-5 p-5 lg:grid-cols-[1.1fr_1fr]">
                <div className="space-y-4">
                  <div className="overflow-hidden rounded-2xl border border-border/60 bg-muted/20">
                    {dish.image_url ? (
                      <img src={dish.image_url} alt={dish.dish_name_zh || `招牌菜 ${index + 1}`} className="aspect-[16/9] w-full object-cover" />
                    ) : (
                      <div className="flex aspect-[16/9] items-center justify-center bg-muted text-sm text-muted-foreground">暂无菜品图片</div>
                    )}
                  </div>
                  <input
                    ref={(node) => {
                      fileInputsRef.current[dish.id] = node;
                    }}
                    type="file"
                    accept="image/*"
                    className="hidden"
                    onChange={(e) => handleImageChange(dish.id, e.target.files?.[0])}
                  />
                  <Button type="button" variant="outline" className="w-full" onClick={() => fileInputsRef.current[dish.id]?.click()}>
                    <ImagePlus className="h-4 w-4" />
                    更换菜品图片
                  </Button>
                </div>

                <div className="space-y-4">
                  <div className="space-y-2">
                    <p className="text-xs font-semibold tracking-[0.18em] text-primary">可编辑 · 菜品标题</p>
                    <Input
                      value={dish.dish_name_zh || ""}
                      onChange={(e) => updateDish(dish.id, { dish_name_zh: e.target.value, dish_name_en: e.target.value, dish_name_pt: e.target.value })}
                      placeholder="输入菜品标题"
                    />
                  </div>
                  <div className="space-y-2">
                    <p className="text-xs font-semibold tracking-[0.18em] text-primary">可编辑 · 菜品详解</p>
                    <Textarea
                      value={dish.description_zh || ""}
                      onChange={(e) => updateDish(dish.id, { description_zh: e.target.value, description_en: e.target.value, description_pt: e.target.value })}
                      placeholder="输入菜品介绍、风味、食材亮点..."
                      className="min-h-[160px]"
                    />
                  </div>
                  <div className="rounded-2xl border border-border/60 bg-muted/20 p-4">
                    <div className="mb-2 flex items-center justify-between">
                      <p className="flex items-center gap-2 text-sm font-semibold text-foreground">
                        <Sparkles className="h-4 w-4 text-primary" />
                        《黄帝内经》解读（系统生成）
                      </p>
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        onClick={() => handleRegenerateNeijing(dish)}
                        disabled={generatingNeijingIds.includes(dish.id) || dish.id.startsWith("draft-")}
                      >
                        {generatingNeijingIds.includes(dish.id) ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <RefreshCw className="h-3.5 w-3.5" />}
                        {generatingNeijingIds.includes(dish.id) ? "生成中..." : "重新生成"}
                      </Button>
                    </div>
                    <p className="whitespace-pre-wrap text-sm leading-7 text-muted-foreground">
                      {dish.neijing_zh || '暂未生成，请先保存菜品后点击"重新生成"按钮。'}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>
          );
        })}
      </div>
    </section>
  );
};